const crypto = require('crypto');

function generateSecureToken(length = 32) {
  return crypto.randomBytes(length).toString('hex');
}

function hashToken(token) {
  return crypto.createHash('sha256').update(token).digest('hex');
}

function setSecureCookie(name, value, days) {
  const date = new Date();
  date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
  const expires = `expires=${date.toUTCString()}`;
  document.cookie = `${name}=${value};${expires};path=/;Secure;HttpOnly;SameSite=Strict`;
}

function getCookie(name) {
  const nameEQ = name + "=";
  const ca = document.cookie.split(';');
  for(let i = 0; i < ca.length; i++) {
    let c = ca[i];
    while (c.charAt(0) === ' ') c = c.substring(1, c.length);
    if (c.indexOf(nameEQ) === 0) return c.substring(nameEQ.length, c.length);
  }
  return null;
}

function deleteCookie(name) {
  document.cookie = `${name}=;expires=Thu, 01 Jan 1970 00:00:00 UTC;path=/;`;
}

const rememberMeTokens = new Map();

function storeRememberMeToken(userId, token, hashedToken) {
  const expiresAt = new Date();
  expiresAt.setDate(expiresAt.getDate() + 30);
  
  rememberMeTokens.set(hashedToken, {
    userId: userId,
    expiresAt: expiresAt
  });
}

function validateRememberMeToken(token) {
  const hashedToken = hashToken(token);
  const tokenData = rememberMeTokens.get(hashedToken);
  
  if (!tokenData) {
    return null;
  }
  
  if (new Date() > tokenData.expiresAt) {
    rememberMeTokens.delete(hashedToken);
    return null;
  }
  
  return tokenData.userId;
}

function removeRememberMeToken(token) {
  const hashedToken = hashToken(token);
  rememberMeTokens.delete(hashedToken);
}

function handleLogin(username, password, rememberMe, userDatabase) {
  const user = userDatabase.find(u => u.username === username);
  
  if (!user) {
    return { success: false, message: 'Invalid credentials' };
  }
  
  const passwordHash = crypto.createHash('sha256').update(password).digest('hex');
  
  if (user.passwordHash !== passwordHash) {
    return { success: false, message: 'Invalid credentials' };
  }
  
  if (rememberMe) {
    const token = generateSecureToken();
    const hashedToken = hashToken(token);
    
    storeRememberMeToken(user.id, token, hashedToken);
    
    setSecureCookie('remember_token', token, 30);
  }
  
  return { success: true, userId: user.id, username: user.username };
}

function attemptAutoLogin(userDatabase) {
  const token = getCookie('remember_token');
  
  if (!token) {
    return null;
  }
  
  const userId = validateRememberMeToken(token);
  
  if (!userId) {
    deleteCookie('remember_token');
    return null;
  }
  
  const user = userDatabase.find(u => u.id === userId);
  
  if (!user) {
    deleteCookie('remember_token');
    removeRememberMeToken(token);
    return null;
  }
  
  return { userId: user.id, username: user.username };
}

function handleLogout() {
  const token = getCookie('remember_token');
  
  if (token) {
    removeRememberMeToken(token);
    deleteCookie('remember_token');
  }
}

function cleanupExpiredTokens() {
  const now = new Date();
  for (const [hashedToken, tokenData] of rememberMeTokens.entries()) {
    if (now > tokenData.expiresAt) {
      rememberMeTokens.delete(hashedToken);
    }
  }
}

